module RefModule(
        input  clk_i,
        input  rst_i,
        input  ai,
        input  bi,
        output yo
    );reg unused_test;
    always @ (posedge clk_i or posedge rst_i) begin
        if (rst_i) begin
            unused_test <= 1'b0;
        end else begin
            if (ai|bi) begin
                unused_test <= 1'b1;
            end else begin
                unused_test <= 1'b0;
            end
        end
    end
   assign yo = unused_test;
endmodule
